const express = require('express');
const crypto = require('crypto');

const app = express();
app.use(express.json());
app.use(express.urlencoded({ extended: true }));

let clients = {
  'client_id': { client_secret: 'client_secret' }
};

let authorizationCodes = {};

app.get('/authorize', (req, res) => {
  const { response_type, client_id, redirect_uri } = req.query;

  if (!response_type || !client_id || !redirect_uri) {
    return res.status(400).send('Invalid request');
  }

  if (response_type !== 'code') {
    return res.status(400).send('Unsupported response type');
  }

  if (!clients[client_id]) {
    return res.status(401).send('Unauthorized client');
  }

  const authorizationCode = crypto.randomBytes(20).toString('hex');
  authorizationCodes[authorizationCode] = { client_id, redirect_uri };

  const consentUrl = `${redirect_uri}?code=${authorizationCode}&state=approved`;
  res.redirect(consentUrl);
});

app.post('/token', (req, res) => {
  const { grant_type, code, redirect_uri, client_id, client_secret } = req.body;

  if (!grant_type || !code || !redirect_uri || !client_id || !client_secret) {
    return res.status(400).send('Invalid request');
  }

  if (grant_type !== 'authorization_code') {
    return res.status(400).send('Unsupported grant type');
  }

  const authCode = authorizationCodes[code];
  if (!authCode || authCode.redirect_uri !== redirect_uri || clients[client_id].client_secret !== client_secret) {
    return res.status(401).send('Unauthorized');
  }

  delete authorizationCodes[code];

  const accessToken = crypto.randomBytes(20).toString('hex');
  res.json({ access_token: accessToken, token_type: 'Bearer', expires_in: 3600 });
});

